"use client"

import { TokenListUI } from "./token-list-ui"
import {
  useTokenList,
  type UseTokenListOptions,
  type TokenHolding,
  type TokenProtocol,
} from "./use-token-list"

// ---------------------------------------------------------------------------
// Re-exports
// ---------------------------------------------------------------------------

export { TokenListUI, type TokenListUIProps } from "./token-list-ui"
export {
  useTokenList,
  type UseTokenListOptions,
  type UseTokenListReturn,
  type TokenHolding,
  type TokenType,
  type TokenProtocol,
} from "./use-token-list"

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export interface TokenListProps {
  /** BSV payment address to fetch token holdings for */
  address: string | null
  /** Token IDs to fetch balances for */
  tokenIds?: string[]
  /** Pre-populated token holdings (skips API fetch for tokens with matching IDs) */
  tokens?: TokenHolding[]
  /** Custom API base URL (default: https://api.1sat.app) */
  apiUrl?: string
  /** ORDFS base URL for icon resolution (default: https://ordfs.network) */
  ordfsBase?: string
  /** Filter by protocol type (default: "all") */
  protocol?: TokenProtocol
  /** Whether to auto-fetch on mount (default: true) */
  autoFetch?: boolean
  /** Callback when a token row is selected */
  onSelect?: (token: TokenHolding) => void
  /** Callback when an external link action is triggered. Receives the URL string. */
  onExternalLink?: (url: string) => void
  /** Number of skeleton rows to show while loading (default: 3) */
  skeletonCount?: number
  /** Optional CSS class name */
  className?: string
}

// ---------------------------------------------------------------------------
// Composed component
// ---------------------------------------------------------------------------

/**
 * Displays a list of BSV20/BSV21 fungible token holdings with balances,
 * icons, and token details. Composes the `useTokenList` hook with the
 * `TokenListUI` presentation component.
 *
 * Requires a BSV address and a list of token IDs. Token details and balances
 * are fetched from the 1Sat API.
 *
 * @example
 * ```tsx
 * import { TokenList } from "@/components/blocks/token-list"
 *
 * function WalletTokens() {
 *   return (
 *     <TokenList
 *       address="1A1zP1eP5QGefi2DMPTfTL5SLmv7DivfNa"
 *       tokenIds={["abc123_0", "def456_0"]}
 *       onSelect={(token) => console.log("Selected:", token.symbol)}
 *     />
 *   )
 * }
 * ```
 */
export function TokenList({
  address,
  tokenIds,
  tokens: prePopulated,
  apiUrl,
  ordfsBase,
  protocol,
  autoFetch,
  onSelect,
  onExternalLink,
  skeletonCount,
  className,
}: TokenListProps) {
  const { tokens, isLoading, error } = useTokenList({
    address,
    tokenIds,
    tokens: prePopulated,
    apiUrl,
    ordfsBase,
    protocol,
    autoFetch,
  })

  return (
    <TokenListUI
      tokens={tokens}
      isLoading={isLoading}
      error={error}
      onSelect={onSelect}
      onExternalLink={onExternalLink}
      skeletonCount={skeletonCount}
      className={className}
    />
  )
}

"use client"

import { useCallback } from "react"
import { Coins, ExternalLink } from "lucide-react"
import { cn } from "@/lib/utils"
import { Button } from "@/components/ui/button"
import { Card, CardContent } from "@/components/ui/card"
import { Badge } from "@/components/ui/badge"
import { Skeleton } from "@/components/ui/skeleton"
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar"
import { Separator } from "@/components/ui/separator"
import type { TokenHolding, TokenProtocol, TokenType } from "./use-token-list"

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export interface TokenListUIProps {
  /** Token holdings to display */
  tokens: TokenHolding[]
  /** Whether the list is loading */
  isLoading: boolean
  /** Error from the last fetch attempt */
  error: Error | null
  /** Callback when a token row is selected */
  onSelect?: (token: TokenHolding) => void
  /** Callback when an external link action is triggered (e.g. view on explorer). Receives the URL string. */
  onExternalLink?: (url: string) => void
  /** Filter displayed tokens by protocol type (default: "all"). Useful when tokens are pre-populated. */
  protocol?: TokenProtocol
  /** Number of skeleton rows to show while loading (default: 3) */
  skeletonCount?: number
  /** Optional CSS class name */
  className?: string
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

/**
 * Format a raw token amount with the given decimal precision.
 *
 * For example, amount "1500000" with decimals 4 becomes "150.0000".
 */
function formatTokenAmount(amount: string, decimals: number): string {
  if (decimals === 0) {
    return BigInt(amount).toLocaleString()
  }

  const raw = amount.padStart(decimals + 1, "0")
  const intPart = raw.slice(0, -decimals) || "0"
  const decPart = raw.slice(-decimals)

  // Format integer part with locale grouping
  const formattedInt = BigInt(intPart).toLocaleString()

  // Trim trailing zeros from decimal part, keep at least 2 digits
  const trimmed = decPart.replace(/0+$/, "")
  const displayDec = trimmed.length < 2 ? decPart.slice(0, 2) : trimmed

  return `${formattedInt}.${displayDec}`
}

/** Badge variant based on token type */
function typeBadgeVariant(
  type: TokenType
): "default" | "secondary" | "outline" {
  return type === "BSV21" ? "default" : "secondary"
}

/** Truncate a token ID for display */
function truncateId(id: string, maxLen = 16): string {
  if (id.length <= maxLen) return id
  return `${id.slice(0, 8)}...${id.slice(-6)}`
}

// ---------------------------------------------------------------------------
// Sub-components
// ---------------------------------------------------------------------------

interface TokenRowProps {
  token: TokenHolding
  onSelect?: (token: TokenHolding) => void
  onExternalLink?: (url: string) => void
  isLast: boolean
}

function TokenRow({ token, onSelect, onExternalLink, isLast }: TokenRowProps) {
  const handleClick = useCallback(() => {
    onSelect?.(token)
  }, [onSelect, token])

  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent) => {
      if (e.key === "Enter" || e.key === " ") {
        e.preventDefault()
        onSelect?.(token)
      }
    },
    [onSelect, token]
  )

  const handleExternalLink = useCallback(
    (e: React.MouseEvent) => {
      e.stopPropagation()
      const url = `https://whatsonchain.com/tx/${token.tokenId.split("_")[0]}`
      onExternalLink?.(url)
    },
    [onExternalLink, token.tokenId]
  )

  const isInteractive = !!onSelect

  return (
    <>
      <div
        role={isInteractive ? "button" : undefined}
        tabIndex={isInteractive ? 0 : undefined}
        className={cn(
          "flex items-center gap-4 px-4 py-3",
          isInteractive &&
            "cursor-pointer transition-colors hover:bg-muted/50 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 rounded-md"
        )}
        onClick={isInteractive ? handleClick : undefined}
        onKeyDown={isInteractive ? handleKeyDown : undefined}
        aria-label={
          isInteractive
            ? `Select ${token.symbol} token, balance ${formatTokenAmount(token.balance, token.decimals)}`
            : undefined
        }
      >
        {/* Token icon */}
        <Avatar className="size-10 flex-shrink-0">
          {token.iconUrl && (
            <AvatarImage
              src={token.iconUrl}
              alt={`${token.symbol} icon`}
            />
          )}
          <AvatarFallback className="bg-muted text-muted-foreground text-xs font-medium">
            {token.symbol.slice(0, 2).toUpperCase()}
          </AvatarFallback>
        </Avatar>

        {/* Symbol + balance */}
        <div className="flex-1 min-w-0">
          <div className="flex items-center gap-2">
            <span className="font-semibold text-sm text-foreground truncate">
              {token.symbol}
            </span>
            <Badge
              variant={typeBadgeVariant(token.type)}
              className="text-[10px] px-1.5 py-0 h-5"
            >
              {token.type}
            </Badge>
          </div>
          <p className="text-sm text-muted-foreground tabular-nums">
            {formatTokenAmount(token.balance, token.decimals)}
          </p>
        </div>

        {/* Token ID + external link */}
        <div className="flex items-center gap-2">
          <span className="text-xs text-muted-foreground font-mono truncate max-w-[120px] hidden sm:block">
            {truncateId(token.tokenId)}
          </span>
          {onExternalLink && (
            <Button
              variant="ghost"
              size="icon"
              className="size-7 flex-shrink-0"
              onClick={handleExternalLink}
              aria-label={`View ${token.symbol} on explorer`}
            >
              <ExternalLink data-icon className="size-3.5 text-muted-foreground" />
            </Button>
          )}
        </div>
      </div>
      {!isLast && <Separator />}
    </>
  )
}

function SkeletonRow({ isLast }: { isLast: boolean }) {
  return (
    <>
      <div className="flex items-center gap-4 px-4 py-3">
        <Skeleton className="size-10 rounded-full flex-shrink-0" />
        <div className="flex-1 flex flex-col gap-2">
          <div className="flex items-center gap-2">
            <Skeleton className="h-4 w-20" />
            <Skeleton className="h-5 w-12 rounded-full" />
          </div>
          <Skeleton className="h-3.5 w-28" />
        </div>
        <Skeleton className="h-3 w-24 hidden sm:block" />
      </div>
      {!isLast && <Separator />}
    </>
  )
}

// ---------------------------------------------------------------------------
// Main UI
// ---------------------------------------------------------------------------

/**
 * Pure presentation component for a list of fungible token holdings.
 *
 * Renders loading skeletons, an empty state, an error state, or the
 * token list rows. All data and callbacks are provided via props.
 */
export function TokenListUI({
  tokens,
  isLoading,
  error,
  onSelect,
  onExternalLink,
  protocol = "all",
  skeletonCount = 3,
  className,
}: TokenListUIProps) {
  // Apply client-side protocol filter when tokens are pre-populated
  const filteredTokens =
    protocol === "all"
      ? tokens
      : tokens.filter((t) => t.type.toLowerCase() === protocol)

  // Loading state
  if (isLoading && filteredTokens.length === 0) {
    return (
      <Card className={cn("w-full", className)}>
        <CardContent className="p-0">
          {Array.from({ length: skeletonCount }, (_, i) => (
            <SkeletonRow
              key={`skeleton-${i}`}
              isLast={i === skeletonCount - 1}
            />
          ))}
        </CardContent>
      </Card>
    )
  }

  // Error state
  if (error) {
    return (
      <Card className={cn("w-full", className)}>
        <CardContent className="flex flex-col items-center gap-2 py-10">
          <Coins
            className="size-10 text-destructive/60"
            aria-hidden="true"
          />
          <p className="text-sm font-medium text-destructive">
            Failed to load tokens
          </p>
          <p className="text-xs text-muted-foreground">{error.message}</p>
        </CardContent>
      </Card>
    )
  }

  // Empty state
  if (filteredTokens.length === 0) {
    return (
      <Card className={cn("w-full", className)}>
        <CardContent className="flex flex-col items-center gap-2 py-10">
          <Coins
            className="size-10 text-muted-foreground/50"
            aria-hidden="true"
          />
          <p className="text-sm text-muted-foreground">No tokens found</p>
        </CardContent>
      </Card>
    )
  }

  // Token list
  return (
    <Card className={cn("w-full overflow-hidden", className)}>
      <CardContent className="p-0">
        {filteredTokens.map((token, index) => (
          <TokenRow
            key={token.tokenId}
            token={token}
            onSelect={onSelect}
            onExternalLink={onExternalLink}
            isLast={index === filteredTokens.length - 1}
          />
        ))}
      </CardContent>
    </Card>
  )
}

import { useCallback, useEffect, useMemo, useRef, useState } from "react"

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

/** Token standard */
export type TokenType = "BSV20" | "BSV21"

/** Protocol filter for token queries */
export type TokenProtocol = "bsv20" | "bsv21" | "all"

/** A single fungible token holding */
export interface TokenHolding {
  /** Token contract/inscription ID */
  tokenId: string
  /** Token symbol or ticker */
  symbol: string
  /** Token type standard */
  type: TokenType
  /** Raw balance as a string (before decimal adjustment) */
  balance: string
  /** Decimal precision for the token */
  decimals: number
  /** ORDFS URL for the token icon (nullable). Pre-populated values skip ORDFS lookup. */
  iconUrl: string | null
}

/** Shape returned from the 1sat API for a BSV21 token */
interface Bsv21TokenResponse {
  id: string
  sym: string
  icon: string | null
  dec: number
  amt: string
}

/** Shape returned from the 1sat API for a BSV20 token */
interface Bsv20TokenResponse {
  tick: string
  dec: number
  amt: string
  icon?: string | null
}

/** Shape returned from the balance endpoint */
interface TokenBalanceResponse {
  confirmed: string
  pending: string
}

export interface UseTokenListOptions {
  /** BSV payment address to fetch token holdings for */
  address: string | null
  /** Token IDs to fetch. When provided, only these tokens are fetched. */
  tokenIds?: string[]
  /** Pre-populated token holdings (skips API fetch for tokens with matching IDs) */
  tokens?: TokenHolding[]
  /** Custom API base URL (default: https://api.1sat.app) */
  apiUrl?: string
  /** ORDFS base URL for icon resolution (default: https://ordfs.network) */
  ordfsBase?: string
  /** Filter by protocol type (default: "all") */
  protocol?: TokenProtocol
  /** Whether to auto-fetch on mount / address change (default: true) */
  autoFetch?: boolean
}

export interface UseTokenListReturn {
  /** List of token holdings */
  tokens: TokenHolding[]
  /** Whether the initial fetch is in progress */
  isLoading: boolean
  /** Error from the last fetch attempt */
  error: Error | null
  /** Manually trigger a refetch */
  refetch: () => void
}

// ---------------------------------------------------------------------------
// Constants
// ---------------------------------------------------------------------------

const DEFAULT_API_URL = "https://api.1sat.app"
const DEFAULT_ORDFS_BASE = "https://ordfs.network"

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function ordfsIconUrl(tokenId: string, ordfsBase: string): string {
  return `${ordfsBase}/${tokenId}`
}

async function fetchJson<T>(url: string, signal?: AbortSignal): Promise<T> {
  const res = await fetch(url, { signal })
  if (!res.ok) {
    throw new Error(`HTTP ${res.status}: ${url}`)
  }
  return res.json() as Promise<T>
}

// ---------------------------------------------------------------------------
// Hook
// ---------------------------------------------------------------------------

/**
 * Fetches BSV20/BSV21 fungible token holdings for a given address.
 *
 * When `tokenIds` are provided, fetches details and balances for those
 * specific tokens. Otherwise the caller should provide a pre-populated list
 * or rely on wallet integration that surfaces token IDs.
 *
 * @example
 * ```ts
 * const { tokens, isLoading, error, refetch } = useTokenList({
 *   address: "1A1zP1eP5QGefi2DMPTfTL5SLmv7DivfNa",
 *   tokenIds: ["abc123_0", "def456_0"],
 * })
 * ```
 */
export function useTokenList(
  options: UseTokenListOptions
): UseTokenListReturn {
  const {
    address,
    tokenIds,
    tokens: prePopulated,
    apiUrl = DEFAULT_API_URL,
    ordfsBase = DEFAULT_ORDFS_BASE,
    protocol = "all",
    autoFetch = true,
  } = options

  const [tokens, setTokens] = useState<TokenHolding[]>([])
  const [isLoading, setIsLoading] = useState(false)
  const [error, setError] = useState<Error | null>(null)
  const abortRef = useRef<AbortController | null>(null)

  // Stable stringified token ID list for dependency tracking
  const tokenIdKey = useMemo(
    () => (tokenIds ? tokenIds.slice().sort().join(",") : ""),
    [tokenIds]
  )

  // Build a lookup map from pre-populated tokens for fast access
  const prePopulatedMap = useMemo(() => {
    if (!prePopulated) return null
    const map = new Map<string, TokenHolding>()
    for (const t of prePopulated) {
      map.set(t.tokenId, t)
    }
    return map
  }, [prePopulated])

  const fetchTokens = useCallback(async () => {
    if (!address || !tokenIds || tokenIds.length === 0) {
      setTokens([])
      return
    }

    abortRef.current?.abort()
    const controller = new AbortController()
    abortRef.current = controller

    setIsLoading(true)
    setError(null)

    try {
      const holdings: TokenHolding[] = await Promise.all(
        tokenIds.map(async (id) => {
          // If a pre-populated holding exists with this ID, use it directly
          const existing = prePopulatedMap?.get(id)
          if (existing) {
            return existing
          }

          // Try BSV21 first, then BSV20
          let symbol = id.slice(0, 8)
          let tokenType: TokenType = "BSV21"
          let decimals = 0
          let hasIcon = false
          let balanceEndpoint = `${apiUrl}/1sat/bsv21/${id}/p2pkh/${address}/balance`

          try {
            const detail = await fetchJson<Bsv21TokenResponse>(
              `${apiUrl}/1sat/bsv21/${id}`,
              controller.signal
            )
            symbol = detail.sym || id.slice(0, 8)
            tokenType = "BSV21"
            decimals = detail.dec ?? 0
            hasIcon = !!detail.icon
          } catch {
            // BSV21 lookup failed, try BSV20
            try {
              const detail20 = await fetchJson<Bsv20TokenResponse>(
                `${apiUrl}/1sat/bsv20/${id}`,
                controller.signal
              )
              symbol = detail20.tick || id.slice(0, 8)
              tokenType = "BSV20"
              decimals = detail20.dec ?? 0
              hasIcon = !!detail20.icon
              balanceEndpoint = `${apiUrl}/1sat/bsv20/${id}/p2pkh/${address}/balance`
            } catch {
              // Neither endpoint found; keep defaults
            }
          }

          // Fetch balance for this token + address
          let balance = "0"
          try {
            const balanceData = await fetchJson<TokenBalanceResponse>(
              balanceEndpoint,
              controller.signal
            )
            // Combine confirmed + pending
            const confirmed = BigInt(balanceData.confirmed || "0")
            const pending = BigInt(balanceData.pending || "0")
            balance = (confirmed + pending).toString()
          } catch {
            // Balance endpoint may 404 if no holdings; that is OK
            balance = "0"
          }

          return {
            tokenId: id,
            symbol,
            type: tokenType,
            balance,
            decimals,
            iconUrl: hasIcon ? ordfsIconUrl(id, ordfsBase) : null,
          }
        })
      )

      // Apply protocol filter
      const filtered =
        protocol === "all"
          ? holdings
          : holdings.filter(
              (h) => h.type.toLowerCase() === protocol
            )

      setTokens(filtered)
    } catch (err) {
      if (err instanceof DOMException && err.name === "AbortError") return
      const fetchError =
        err instanceof Error ? err : new Error("Failed to fetch tokens")
      setError(fetchError)
      setTokens([])
    } finally {
      setIsLoading(false)
    }
  }, [address, tokenIdKey, apiUrl, ordfsBase, protocol, prePopulatedMap])

  // Auto-fetch on mount / dependency change
  useEffect(() => {
    if (autoFetch && address && tokenIds && tokenIds.length > 0) {
      void fetchTokens()
    }

    return () => {
      abortRef.current?.abort()
    }
  }, [autoFetch, fetchTokens, address, tokenIdKey])

  return {
    tokens,
    isLoading,
    error,
    refetch: fetchTokens,
  }
}
